import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a request to equip a specific Name Icon.
 * Mirrors the server-side ChangeNameIconEvent handler.
 */
export class ChangeNameIconComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(iconId: number) {
        this._data = [iconId];
        console.log(
            `[📤] ChangeNameIconComposer → equipping name icon ${iconId}`
        );
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
